SELECT role_id AS roleId, role_name AS roleName, role_code AS roleCode, user_type AS userType, remark, create_time AS createTime, update_time AS updateTime FROM sys_role WHERE is_deleted = 0
AND (role_name LIKE CONCAT('%', #{keyword}, '%') OR role_code LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY role_id ASC LIMIT #{offset}, #{limit}
